-- 011_geography_locations.sql
-- Référentiel géographique pays / régions / villes pour Agri-Control.
-- Granularité : 1 ligne = 1 ville rattachée à un pays et une région.
-- Source logique : régions officielles Maroc + communautés autonomes Espagne ; liste de villes opérationnelle initiale, extensible par INSERT.

CREATE TABLE IF NOT EXISTS geography_locations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  country_id TEXT NOT NULL,
  country_code TEXT NOT NULL,
  country_name TEXT NOT NULL,
  region_id TEXT NOT NULL,
  region_code TEXT NOT NULL,
  region_name TEXT NOT NULL,
  city_id TEXT NOT NULL,
  city_name TEXT NOT NULL,
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  CONSTRAINT geography_locations_country_code_check CHECK (country_code IN ('MA', 'ES')),
  CONSTRAINT geography_locations_unique_city UNIQUE (country_id, region_id, city_id)
);

CREATE INDEX IF NOT EXISTS idx_geography_locations_country ON geography_locations(country_id);
CREATE INDEX IF NOT EXISTS idx_geography_locations_region ON geography_locations(country_id, region_id);
CREATE INDEX IF NOT EXISTS idx_geography_locations_city ON geography_locations(city_name);

ON CONFLICT (country_id, region_id, city_id) DO UPDATE SET
  country_code = EXCLUDED.country_code,
  country_name = EXCLUDED.country_name,
  region_code = EXCLUDED.region_code,
  region_name = EXCLUDED.region_name,
  city_name = EXCLUDED.city_name,
  is_active = TRUE,
  updated_at = NOW();